solution_code:
#include <iostream>

class Animal {
public:
    virtual std::string speak() const { return "Animal"; }
    virtual ~Animal() = default;
};

class Dog : public Animal {
public:
    std::string speak() const override { return "Dog"; }
};

void describeByValue(Animal a) {
    std::cout << "sliced: " << a.speak() << "\n";
}

void describeByRef(const Animal& a) {
    std::cout << "unsliced: " << a.speak() << "\n";
}

int main() {
    Dog d;
    describeByValue(d);
    describeByRef(d);
    return 0;
}

